css:
.loader {
  position: relative;
  display: block;
  width: 220px;
  height: 220px;
  border-radius: 50%;
  border: solid 5px transparent;
  overflow: visible;
  isolation: isolate;
  transform-style: flat;
  box-shadow:
    5px 5px 5px rgb(12, 12, 12),
    inset 5px 5px 5px rgb(24, 23, 23),
    inset -1px -1px 10px rgba(153, 148, 148, 0.432),
    -1px -1px 10px rgba(206, 198, 198, 0.281);
}

.loader::before {
  content: "";
  position: absolute;
  z-index: 1;
  width: 180px;
  height: 180px;
  border-radius: 50%;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  box-shadow: 5px 5px 20px black, -2px -2px 40px black;
  background: repeating-conic-gradient(
    rgb(61, 59, 59) 0%,
    rgba(248, 248, 246, 0.534) 15%,
    rgb(54, 52, 52) 33.33%
  );
}

.ball {
  --phase: 0deg;
  --orbit-radius: 97.5px;
  --ball-size: 15px;

  position: absolute;
  z-index: 2;
  top: 50%;
  left: 50%;
  width: var(--ball-size);
  height: var(--ball-size);
  margin: calc(var(--ball-size) / -2) 0 0 calc(var(--ball-size) / -2);
  display: block;
  border-radius: 50%;
  background: radial-gradient(
    circle at 35% 35%,
    rgb(255, 255, 255) 1%,
    rgb(5, 5, 5) 55%
  );
  transform: rotate(var(--phase)) translateX(var(--orbit-radius));
  animation: rotate var(--loader-speed, 5s) infinite linear;
  backface-visibility: hidden;
  will-change: transform;
}

.ball:nth-child(1) { --phase: 0deg; }
.ball:nth-child(2) { --phase: 45deg; }
.ball:nth-child(3) { --phase: 90deg; }
.ball:nth-child(4) { --phase: 135deg; }
.ball:nth-child(5) { --phase: 180deg; }
.ball:nth-child(6) { --phase: 225deg; }
.ball:nth-child(7) { --phase: 270deg; }
.ball:nth-child(8) { --phase: 315deg; }

@keyframes rotate {
  from {
    transform: rotate(var(--phase)) translateX(var(--orbit-radius));
  }

  to {
    transform: rotate(calc(var(--phase) + 360deg)) translateX(var(--orbit-radius));
  }
}
